import{_ as e,o as r,c as t,a2 as s}from"./chunks/framework.BS3ZfcoS.js";const u=JSON.parse('{"title":"面试急救包","description":"","frontmatter":{"title":"面试急救包","author":"","collection":"职场成长","series_order":8,"total_chars":930},"headers":[],"relativePath":"career/interview-kit.md","filePath":"career/interview-kit.md"}'),o={name:"career/interview-kit.md"};function n(i,a,h,l,p,d){return r(),t("div",null,[...a[0]||(a[0]=[s('<h2 id="s-530" tabindex="-1">面试急救包系列 <a class="header-anchor" href="#s-530" aria-label="Permalink to &quot;面试急救包系列 {#s-530}&quot;">​</a></h2><p>共4个视频</p><h3 id="s-531" tabindex="-1">【面试社恐必看】自我介绍3步法当场拿offer <a class="header-anchor" href="#s-531" aria-label="Permalink to &quot;【面试社恐必看】自我介绍3步法当场拿offer {#s-531}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-532" tabindex="-1">1. 面试本质不是考试而是建立信任关系——你要让对方意识到你是真诚且靠谱的人 <a class="header-anchor" href="#s-532" aria-label="Permalink to &quot;1. 面试本质不是考试而是建立信任关系——你要让对方意识到你是真诚且靠谱的人 {#s-532}&quot;">​</a></h4><p>**2. **自我介绍三步法：第一步破冰（问称呼、打招呼）→第二步英雄之旅（把经历拆成三段，每段讲旅程多好、收获什么，呈现向上逻辑）→第三步匹配岗位能力（替面试官想好雇佣你的理由）</p><h4 id="s-533" tabindex="-1">3. 英雄之旅的本质是面对过去找力量而非找缺陷，每段旅程都有珍贵宝藏 <a class="header-anchor" href="#s-533" aria-label="Permalink to &quot;3. 英雄之旅的本质是面对过去找力量而非找缺陷，每段旅程都有珍贵宝藏 {#s-533}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「面试的本质不是一场考试，而是跟陌生人建立信任关系」</em></p><p><strong>行动指南</strong></p><p>用英雄之旅逻辑准备自我介绍，替面试官提供雇佣你的理由</p><h3 id="s-534" tabindex="-1">面试急救包：大厂学姐教你面试3步法（一）——第一次面试的血泪教训 <a class="header-anchor" href="#s-534" aria-label="Permalink to &quot;面试急救包：大厂学姐教你面试3步法（一）——第一次面试的血泪教训 {#s-534}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-535" tabindex="-1">1. 第一次面试常犯的错误：焦虑外表穿着、迟到、毫无工作经验 <a class="header-anchor" href="#s-535" aria-label="Permalink to &quot;1. 第一次面试常犯的错误：焦虑外表穿着、迟到、毫无工作经验 {#s-535}&quot;">​</a></h4><h4 id="s-536" tabindex="-1">2. 现实冲击——&quot;这个社会没有一个容纳你的位子&quot;时对成年人艰难的深刻共情 <a class="header-anchor" href="#s-536" aria-label="Permalink to &quot;2. 现实冲击——&quot;这个社会没有一个容纳你的位子&quot;时对成年人艰难的深刻共情 {#s-536}&quot;">​</a></h4><p>**3. **很多面试错误从一开始就可以避免，关键在于提前准备，按面试前中后三阶段系统规划</p><p><strong>金句</strong></p><p><em>「95年不小了，是时候该走出象牙塔了」</em></p><p><strong>行动指南</strong></p><p>按面试前中后三阶段系统准备，避免新人常见错误</p><h3 id="s-537" tabindex="-1">面试急救包：大厂学姐教你面试3步法（二）——面试前与面试中 <a class="header-anchor" href="#s-537" aria-label="Permalink to &quot;面试急救包：大厂学姐教你面试3步法（二）——面试前与面试中 {#s-537}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-538" tabindex="-1">1. 面试前80%内容可提前准备——问前辈学长或购买靠谱课程学习面试逻辑 <a class="header-anchor" href="#s-538" aria-label="Permalink to &quot;1. 面试前80%内容可提前准备——问前辈学长或购买靠谱课程学习面试逻辑 {#s-538}&quot;">​</a></h4><p>**2. **自我介绍三步：先破冰问称呼→只讲工作成功案例和亮点（不是照着简历念）→匹配岗位需求</p><h4 id="s-539" tabindex="-1">3. 提前演练自我介绍，一上来做漂亮就能把握主动权 <a class="header-anchor" href="#s-539" aria-label="Permalink to &quot;3. 提前演练自我介绍，一上来做漂亮就能把握主动权 {#s-539}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「你的自我介绍只讲工作里面的成功案例，你最主要最牛逼的成绩是什么，要有亮点，有亮点对方才会记住你」</em></p><p><strong>行动指南</strong></p><p>提前准备并多次演练自我介绍，确保开始就有好感</p><h3 id="s-540" tabindex="-1">面试急救包：大厂学姐教你面试3步法（三）——面试后 <a class="header-anchor" href="#s-540" aria-label="Permalink to &quot;面试急救包：大厂学姐教你面试3步法（三）——面试后 {#s-540}&quot;">​</a></h3><p><strong>核心观点</strong></p><h4 id="s-541" tabindex="-1">1. 面试后礼貌要反馈——当场问面试官对你的兴趣程度及原因，获取直接反馈 <a class="header-anchor" href="#s-541" aria-label="Permalink to &quot;1. 面试后礼貌要反馈——当场问面试官对你的兴趣程度及原因，获取直接反馈 {#s-541}&quot;">​</a></h4><h4 id="s-542" tabindex="-1">2. 建立面试总文档记录每次面试的问题和反馈，面试官也有值得你学习的地方 <a class="header-anchor" href="#s-542" aria-label="Permalink to &quot;2. 建立面试总文档记录每次面试的问题和反馈，面试官也有值得你学习的地方 {#s-542}&quot;">​</a></h4><p>**3. **哪怕失败的面试也有价值——让你知道不足；成功的经验话术可复用；找到并证明你的价值就是最好的成人礼</p><p><strong>金句</strong></p><p><em>「找到并且证明你的价值就是最好的成人礼」</em></p><p><strong>行动指南</strong></p><p>面试后主动要反馈，建立面试总文档做复盘</p>',38)])])}const m=e(o,[["render",n]]);export{u as __pageData,m as default};
